import{_ as i,W as e,X as t,a2 as o}from"./framework-5910e262.js";const c={},d=o('<h1 id="git使用小技巧【修改commit注释】" tabindex="-1"><a class="header-anchor" href="#git使用小技巧【修改commit注释】" aria-hidden="true">#</a> Git使用小技巧【修改commit注释】</h1><p>通常有些朋友在 <code>git commit -m &quot;xxxx&quot; file.c</code> 后，觉得注释的内容描述不够精准， 想将<code>&quot;xxxx&quot;</code>修改为<code>&quot;yyyy&quot;</code>, 该如何操作呢？ 通常有以下两种情况：</p><p>第一种： commit之后，将代码<code>git push</code>到远程仓库的</p><p>第二种:：commit之后，还没有<code>push</code>, 代码还在本地仓库的</p><p>如果是第一种情况会多一个步骤</p><h2 id="一、修改最后一次提交的注释" tabindex="-1"><a class="header-anchor" href="#一、修改最后一次提交的注释" aria-hidden="true">#</a> 一、修改最后一次提交的注释</h2><p>首先，如果仅仅是想修改最后一次注释，修改步骤如下：</p><ol><li><code>git commit --amend</code> 【第一行出现注释界面】</li><li><code>i</code> 【进入修改模式, 修改完成】</li><li><code>Esc</code> 【退出编辑模式】</li><li><code>:wq</code> 【保存并退出即可】</li><li><code>git log</code> 【 查看提交记录】</li></ol><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3hpYW95dWxpa2U=,size_16,color_FFFFFF,t_70.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="二、修改以前提交的注释" tabindex="-1"><a class="header-anchor" href="#二、修改以前提交的注释" aria-hidden="true">#</a> 二、修改以前提交的注释</h2><p>当需要修改以前早就提交过的注释时，可按以下步骤修改：</p><ol><li><code>git rebase -i HEAD~2</code> 【数字指的是倒数第n次提交记录的注释】</li><li><code>pick</code> 改成 <code>edit</code> 【输入 i 编辑模式，只需要将你需要修改的注释前的pick 改为 edit 即可】</li><li><code>Esc</code> 【退出编辑模式】</li><li><code>:wq</code> 【保存退出】</li><li><code>git commit --amend</code> 【同上有提示，第一行进行你真正需要的修改, 修改完后，直接输入<code>:wq</code>保存退出】</li><li><code>git rebase --continue</code> 【退出后，输入最后一步】</li></ol><p>图文步骤如下：</p><ol><li><p><code>git rebase -i HEAD~2</code> 会出现此界面</p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/image-20220801115108768.png" alt="image-20220801115108768" tabindex="0" loading="lazy"><figcaption>image-20220801115108768</figcaption></figure></li><li><p>pick 改为 edit 后，退出</p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3hpYW95dWxpa2U=,size_16,color_FFFFFF,t_70-20220801113531370.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure></li><li><p>会出现，非分支，正变基的分支，别害怕，继续往下 <code>git commit --amend</code></p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3hpYW95dWxpa2U=,size_16,color_FFFFFF,t_70-20220801113534544-20220801115001018.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure></li><li><p>第一行修改注释，保存退出</p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3hpYW95dWxpa2U=,size_16,color_FFFFFF,t_70-20220801114957165.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure></li><li><p>最后一步, <code>git rebase --continue</code>, 修改完成啦</p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3hpYW95dWxpa2U=,size_16,color_FFFFFF,t_70-20220801114953877.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure></li><li><p><code>git log</code> 可以查看已经修改成功了</p><figure><img src="https://cdn.jsdelivr.net/gh/hekun97/picture/Git_notes/20210728123421918.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure></li></ol><h2 id="三、已经将代码push到远程仓库的" tabindex="-1"><a class="header-anchor" href="#三、已经将代码push到远程仓库的" aria-hidden="true">#</a> 三、已经将代码push到远程仓库的</h2><p>按照下面的步骤修改：</p><ol><li><p>首先，把最新的版本从远程仓库先pull下来；</p><p><code>git pull origin master</code></p></li><li><p>对最新版本的注释进行修改，修改的方法都如上<code>一</code>和<code>二</code>；</p></li><li><p>最后修改完成后，强制push到远程仓库。</p><p><code>git push --force origin master</code></p></li></ol><blockquote><p>注：很重要的一点是，你最好保证在你强制push之前没有人提交代码，如果在你push之前有人提交了新的代码到远程仓库，然后你又强制push，那么会被你的强制更新覆盖！！！</p><p>push前先使用<code>git status</code>确认下即可。</p></blockquote>',18),a=[d];function p(n,l){return e(),t("div",null,a)}const r=i(c,[["render",p],["__file","git-more-note.html.vue"]]);export{r as default};
